async (params, browser) => {
  // Open product page
  await browser.open(`${params.product_url}`)

  // Wait for page to load
  await browser.waitForSelector('h1, [data-testid=\'product-title\']', 15000)

  // Let page render
  await browser.wait(2000)

  // Scroll to reviews section
  await browser.scroll({ direction: 'down', amount: 3000 })

  await browser.wait(2000)

  // Scroll through reviews
  await browser.scroll({ direction: 'down', amount: 2000 })

  await browser.wait(2000)

  // Scroll further
  await browser.scroll({ direction: 'down', amount: 2000 })

  await browser.wait(1500)

  // Extract reviews
  const reviews_data = await browser.evaluate(`const reviews = []; const reviewEls = document.querySelectorAll('[data-testid="review-card"], [class*="review-card"], [class*="customer-review"], [itemprop="review"]'); for (let i = 0; i < Math.min(reviewEls.length, 20); i++) { const el = reviewEls[i]; const authorEl = el.querySelector('[class*="author"], [itemprop="author"], [class*="reviewer"]'); const ratingEl = el.querySelector('[class*="rating"] [class*="stars"], [itemprop="ratingValue"]'); const titleEl = el.querySelector('[class*="review-title"], h3, h4'); const contentEl = el.querySelector('[class*="review-text"], [itemprop="reviewBody"], [class*="review-body"]'); const dateEl = el.querySelector('[class*="date"], time, [itemprop="datePublished"]'); const verifiedEl = el.querySelector('[class*="verified"], [class*="badge"]'); reviews.push({ author: authorEl ? authorEl.textContent.trim() : 'Anonymous', rating: ratingEl ? ratingEl.textContent.trim() : '', title: titleEl ? titleEl.textContent.trim() : '', content: contentEl ? contentEl.textContent.trim().substring(0, 800) : '', date: dateEl ? dateEl.textContent.trim() : '', verified_purchase: !!verifiedEl }); } const overallRatingEl = document.querySelector('[itemprop="ratingValue"], [data-testid="reviews-stars"]'); const totalReviewsEl = document.querySelector('[itemprop="reviewCount"], [data-testid="reviews-count"]'); return { overall_rating: overallRatingEl ? overallRatingEl.textContent.trim() : '', total_reviews: totalReviewsEl ? totalReviewsEl.textContent.trim() : '', scraped_count: reviews.length, reviews: reviews, url: window.location.href }`)

  return reviews_data
}
